import{_ as a,o,c as e,ae as i}from"./chunks/framework.Czhw_PXq.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":"left"},"headers":[],"relativePath":"note/应急响应.md","filePath":"note/应急响应.md"}'),p={name:"note/应急响应.md"};function n(r,t,l,s,h,d){return o(),e("div",null,[...t[0]||(t[0]=[i('<h2 id="小技巧" tabindex="-1">小技巧： <a class="header-anchor" href="#小技巧" aria-label="Permalink to &quot;小技巧：&quot;">​</a></h2><p>ftp：ftp链接主机时，可以以匿名用户anonymous登录，一般操作切换成binary以二进制模式传输，这样下载的文件不会受到缺损。 在下载多个文件时可以使用mget命令下载 kali自带的hash-identifier可以去识别大概率是哪一种加密方式 md5解密方式: 先把字符串复制到一个文本里面(md5.hash)然后利用jonh 文件名或者使用网站 md5加密方式：echo -n &#39; 要加密的字符串&#39; | md5sum base64解码 echo &quot;要解码的字符串&quot; | base64 -d (-d参数指定要解码而不是编码) searchspoit 漏洞名称 | 下载利用文档 ：searchsploit 漏洞名称 -m +利用文档名字 export TERM=xterm-color /完善环境变量</p><p>telnet登录乱码可以使用chcp 6501</p><h2 id="nmap标准四扫" tabindex="-1">nmap标准四扫: <a class="header-anchor" href="#nmap标准四扫" aria-label="Permalink to &quot;nmap标准四扫:&quot;">​</a></h2><p>sudo nmap -sT --min-rate 10000 -p- ip sudo nmap -sT -sV -sC -O -p- ip sudo nmap -sU -p- ip</p><p>sudo nmap --script=vuln -p- ip</p><h2 id="wireshark" tabindex="-1">Wireshark: <a class="header-anchor" href="#wireshark" aria-label="Permalink to &quot;Wireshark:&quot;">​</a></h2><p>过滤规则: tcp.connection.syn//过滤syn数据请求包,后可跟and连接多个条件语句 ip.src==目标地址 ip.dst==终端地址 http.request.method=//可以筛选基于http的请求如:POSA ,GET</p><p>http contains &quot;字符串&quot; //筛选含有字符串的包</p><h2 id="windows应急响应" tabindex="-1">windows应急响应: <a class="header-anchor" href="#windows应急响应" aria-label="Permalink to &quot;windows应急响应:&quot;">​</a></h2><p>查看注册的用户名: net user; 查看隐藏的用户名可以通过组来查看 net localgroup Administrators</p><p>net localgroup Users;</p><h2 id="linux应急响应" tabindex="-1">linux应急响应 <a class="header-anchor" href="#linux应急响应" aria-label="Permalink to &quot;linux应急响应&quot;">​</a></h2><p>netstat -tunlp ps -ef | grep 进程号 kill -9 //杀进程 cat /etc/rc.local//查看开机自启的脚本</p><p>crontab -e</p><h2 id="内存取证" tabindex="-1">内存取证: <a class="header-anchor" href="#内存取证" aria-label="Permalink to &quot;内存取证:&quot;">​</a></h2><p>​ volatility： ​ python2 volatility.py -f 文件名字 inmaginfo//镜像分析操作系统 ​ python2 volatility.py -f 文件名字 -- profile=WINXP64SP1 printkey -K &quot;SAM\\DOmains\\Account\\USERS\\Names&quot; //查看当前内存镜像中的用户 ​ python2 volatility.py -f 文件名字 -- profile=WINXP64SP1hashdump //查看用户名密码信息,使用jonh爆破（jonh --wordlist=字典 文件 ​ python2 volatility.py -f 文件名字 --profile=Win7SP1x64 printkey -K &quot;ControlSet001\\Control\\ComputerName\\ComputerName&quot;//获取主机名字 ​ python2 volatility.py -f 文件名字 --profile=WINX64SP1 pslist//查看进程 psscan参数可以查看隐藏进程 ​ python2 volatility.py -f 文件名字 --profile=Win7SP1x64 pslist -p PID//查看具体进程 ​ python2 volatility.py -f 文件名字 --profile=WINX64SP1 cmdscan //查看历史命令 ​ python2 volatility.py -f 文件名字 --profile=Win7SP1x64 filescan | grep &quot;flag&quot;//筛选出相应的文件 ​ python2 volatility.py -f 文件名字 --profile=Win7SP1x64 dumpfiles -Q [PID] -D ./ //dump下来对应的文件</p><p>​ python2 volatility.py -f 文件名字 --profile=Win7SP1x64 iehistory //查看浏览器的历史记录</p><h2 id="mysql数据库指令" tabindex="-1">mysql数据库指令 : <a class="header-anchor" href="#mysql数据库指令" aria-label="Permalink to &quot;mysql数据库指令 :&quot;">​</a></h2><p>id =0 union select 1 ,group_concat(schema_name) from (infomation_schema.schemata)//爆库</p><p>kali: sudo -l //看用户有哪些权限</p><p>sudo /usr/bin/php - r &quot;system (&#39;/bin/bash&#39;);&quot;</p>',22)])])}const u=a(p,[["render",n]]);export{m as __pageData,u as default};
